def check_balanced_brackets(self):
    """
    जांचता है कि अभिव्यक्ति में संतुलित ब्रैकेट हैं या नहीं।
    :return: यदि अभिव्यक्ति में संतुलित ब्रैकेट हैं, तो True, अन्यथा False।
    >>> b = BalancedBrackets("a(b)c")
    >>> b.check_balanced_brackets()
    True

    """
    stack = []
    brackets = {
        '(': ')',
        '[': ']',
        '{': '}'
    }
    closing_brackets = set(brackets.values())

    for char in self.expression:
        if char in brackets:
            stack.append(char)
        elif char in closing_brackets:
            if not stack or brackets[stack.pop()] != char:
                return False

    return len(stack) == 0

def calculate_binary_info(self):
    """
    बाइनरी स्ट्रिंग की जानकारी की गणना करें, जिसमें 0 और 1 का प्रतिशत, और बाइनरी स्ट्रिंग की कुल लंबाई शामिल है।
    >>> bdp = BinaryDataProcessor("0110100001100101011011000110110001101110")
    >>> bdp.calculate_binary_info()
    {'Zeroes': 0.475, 'Ones': 0.525, 'Bit length': 40}

    """
    binary_string = self.binary_string
    total_length = len(binary_string)

    if total_length == 0:
        return {'Zeroes': 0.0, 'Ones': 0.0, 'Bit length': 0}

    count_zeroes = binary_string.count('0')
    count_ones = binary_string.count('1')

    percentage_zeroes = count_zeroes / total_length
    percentage_ones = count_ones / total_length

    return {
        'Zeroes': percentage_zeroes,
        'Ones': percentage_ones,
        'Bit length': total_length
    }

def remove_book(self, title, quantity):
    """
    इन्वेंटरी से एक या कई किताबें हटाएं जो किताब के शीर्षक द्वारा क्रमबद्ध है।
    अमान्य इनपुट मिलने पर झूठा उठाएं।
    :param title: str, किताब का शीर्षक
    :param quantity: int
    """
    # Validate input types
    if not isinstance(title, str):
        raise ValueError("Title must be a string")

    if not isinstance(quantity, int):
        raise ValueError("Quantity must be an integer")

    # Validate quantity is positive
    if quantity <= 0:
        raise ValueError("Quantity must be a positive integer")

    # Check if title exists in inventory
    if not hasattr(self, 'inventory'):
        self.inventory = {}

    if title not in self.inventory:
        raise ValueError(f"Book with title '{title}' not found in inventory")

    # Check if sufficient quantity exists
    if self.inventory[title] < quantity:
        raise ValueError(f"Insufficient quantity. Only {self.inventory[title]} copies available")

    # Remove the books
    self.inventory[title] -= quantity

    # Remove entry if quantity becomes 0
    if self.inventory[title] == 0:
        del self.inventory[title]

def calculate(self, expression):
    """
    दिए गए एक्सप्रेशन की वैल्यू कैलकुलेट करें।

    :param expression: string, दिया गया एक्सप्रेशन
    :return: अगर सफल रहा, तो एक्सप्रेशन की वैल्यू रिटर्न करता है; नहीं तो None रिटर्न करता है

    >>> calculator = Calculator()
    >>> calculator.calculate('1+2-3')
    0.0
    """
    try:
        # Remove whitespace
        expression = expression.replace(' ', '')

        if not expression:
            return None

        # Stack to store numbers
        stack = []
        num = 0
        operation = '+'

        for i, char in enumerate(expression):
            if char.isdigit() or char == '.':
                # Build the number (handle multi-digit and decimal numbers)
                if char == '.':
                    # Handle decimal numbers
                    decimal_part = ''
                    j = i + 1
                    while j < len(expression) and expression[j].isdigit():
                        decimal_part += expression[j]
                        j += 1
                    num = float(str(int(num)) + '.' + decimal_part) if decimal_part else float(num)
                else:
                    num = num * 10 + int(char)

            # If current char is an operator or last character
            if char in '+-*/' or i == len(expression) - 1:
                if i == len(expression) - 1 and char.isdigit():
                    # Process the last number
                    pass

                # Apply previous operation
                if operation == '+':
                    stack.append(num)
                elif operation == '-':
                    stack.append(-num)
                elif operation == '*':
                    stack.append(stack.pop() * num)
                elif operation == '/':
                    if num == 0:
                        return None
                    stack.append(stack.pop() / num)

                # Update operation and reset num
                if char in '+-*/':
                    operation = char
                    num = 0

        return float(sum(stack))

    except:
        return None

