def add_table(self, data):
    """
    निर्दिष्ट डेटा के साथ Word दस्तावेज़ में एक तालिका जोड़ता है।
    :param data: सूचियों की सूची, तालिका को भरने के लिए डेटा।
    :return: bool, यदि तालिका सफलतापूर्वक जोड़ी गई है तो True, अन्यथा False।
    """
    try:
        if not data or not isinstance(data, list) or len(data) == 0:
            return False

        # Check if all rows have the same length
        if not all(isinstance(row, list) for row in data):
            return False

        # Get dimensions
        rows = len(data)
        cols = len(data[0]) if data else 0

        if cols == 0:
            return False

        # Verify all rows have same number of columns
        if not all(len(row) == cols for row in data):
            return False

        # Add table to document (assuming self.document is a python-docx Document object)
        table = self.document.add_table(rows=rows, cols=cols)

        # Populate table with data
        for i, row_data in enumerate(data):
            row_cells = table.rows[i].cells
            for j, cell_data in enumerate(row_data):
                row_cells[j].text = str(cell_data)

        return True

    except Exception as e:
        return False

def _get_alignment_value(self, alignment):
    """
    दिए गए संरेखण स्ट्रिंग के अनुसार संरेखण मान लौटाता है।
    :param alignment: str, संरेखण स्ट्रिंग ('left', 'center', या 'right')।
    :return: int, संरेखण मान।
    """
    alignment_map = {
        'left': 0,
        'center': 1,
        'right': 2
    }
    return alignment_map.get(alignment.lower(), 0)

def find_blank(self, state):
    """
    वर्तमान स्थिति का खाली स्थान खोजें, जो 0 तत्व है।
    :param state: एक 3*3 आकार की सूची Integer की, जो वर्तमान स्थिति को संग्रहीत करती है।
    :return i, j: दो Integers, जो खाली ब्लॉक के निर्देशांक का प्रतिनिधित्व करते हैं।
    >>> eightPuzzle = EightPuzzle([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    >>> eightPuzzle.find_blank([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    (2, 1)
    """
    for i in range(len(state)):
        for j in range(len(state[i])):
            if state[i][j] == 0:
                return (i, j)

def move(self, state, direction):
    """
    खाली ब्लॉक को खोजें, फिर दिए गए दिशा में बोर्ड को आगे बढ़ाएं।
    :param state: एक 3*3 आकार की Integer की सूची, जो चलने से पहले की स्थिति को संग्रहीत करती है।
    :param direction: str, केवल 4 दिशाएँ 'up', 'down', 'left', 'right' हैं
    :return new_state: एक 3*3 आकार की Integer की सूची, जो चलने के बाद की स्थिति को संग्रहीत करती है।
    >>> eightPuzzle.move([[2, 3, 4], [5, 8, 1], [6, 0, 7]], 'left')
    [[2, 3, 4], [5, 8, 1], [0, 6, 7]]
    """
    # Create a deep copy of the state to avoid modifying the original
    new_state = [row[:] for row in state]

    # Find the position of the empty block (0)
    empty_row, empty_col = None, None
    for i in range(3):
        for j in range(3):
            if new_state[i][j] == 0:
                empty_row, empty_col = i, j
                break
        if empty_row is not None:
            break

    # Determine the new position based on direction
    # Note: moving the empty block 'left' means swapping with the tile on its left
    if direction == 'left':
        if empty_col > 0:
            # Swap empty block with the tile on its left
            new_state[empty_row][empty_col], new_state[empty_row][empty_col - 1] = \
                new_state[empty_row][empty_col - 1], new_state[empty_row][empty_col]
    elif direction == 'right':
        if empty_col < 2:
            # Swap empty block with the tile on its right
            new_state[empty_row][empty_col], new_state[empty_row][empty_col + 1] = \
                new_state[empty_row][empty_col + 1], new_state[empty_row][empty_col]
    elif direction == 'up':
        if empty_row > 0:
            # Swap empty block with the tile above it
            new_state[empty_row][empty_col], new_state[empty_row - 1][empty_col] = \
                new_state[empty_row - 1][empty_col], new_state[empty_row][empty_col]
    elif direction == 'down':
        if empty_row < 2:
            # Swap empty block with the tile below it
            new_state[empty_row][empty_col], new_state[empty_row + 1][empty_col] = \
                new_state[empty_row + 1][empty_col], new_state[empty_row][empty_col]

    return new_state

def calculate(self, expression):
    """
    दिए गए पोस्टफ़िक्स एक्सप्रेशन का रिज़ल्ट कैलकुलेट करें।

    :param expression: string, कैलकुलेट करने के लिए पोस्टफ़िक्स एक्सप्रेशन
    :return: float, कैलकुलेट किया गया रिज़ल्ट

    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator.calculate("2 + 3 * 4")
    14.0
    """
    # Convert infix to postfix first, then evaluate
    def precedence(op):
        if op in ['+', '-']:
            return 1
        if op in ['*', '/']:
            return 2
        return 0

    def infix_to_postfix(expr):
        stack = []
        postfix = []
        tokens = expr.replace('(', ' ( ').replace(')', ' ) ').split()

        for token in tokens:
            if token.replace('.', '').replace('-', '').isdigit():
                postfix.append(float(token))
            elif token == '(':
                stack.append(token)
            elif token == ')':
                while stack and stack[-1] != '(':
                    postfix.append(stack.pop())
                stack.pop()  # Remove '('
            elif token in ['+', '-', '*', '/']:
                while stack and stack[-1] != '(' and precedence(stack[-1]) >= precedence(token):
                    postfix.append(stack.pop())
                stack.append(token)

        while stack:
            postfix.append(stack.pop())

        return postfix

    def evaluate_postfix(postfix):
        stack = []

        for token in postfix:
            if isinstance(token, float):
                stack.append(token)
            else:
                b = stack.pop()
                a = stack.pop()
                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    stack.append(a / b)

        return stack[0]

    postfix = infix_to_postfix(expression)
    return evaluate_postfix(postfix)

from decimal import Decimal

@staticmethod
def _calculate(first_value, second_value, current_op):
    """
    दिए गए ऑपरेटर और ऑपरेनड के आधार पर गणितीय गणना करें
    :param first_value: string, पहला ऑपरेनड
    :param second_value: string, दूसरा ऑपरेनड
    :param current_op: string, ऑपरेटर
    :return: decimal.Decimal, गणना किया गया परिणाम
    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator._calculate("2", "3", "+")
    5.0

    """
    num1 = Decimal(first_value)
    num2 = Decimal(second_value)

    if current_op == '+':
        return float(num1 + num2)
    elif current_op == '-':
        return float(num1 - num2)
    elif current_op == '*':
        return float(num1 * num2)
    elif current_op == '/':
        return float(num1 / num2)
    elif current_op == '//':
        return float(num1 // num2)
    elif current_op == '%':
        return float(num1 % num2)
    elif current_op == '**':
        return float(num1 ** num2)
    else:
        raise ValueError(f"Unsupported operator: {current_op}")

def get_employee(self, employee_id):
    """
    एचआर प्रबंधन प्रणाली से एक कर्मचारी की जानकारी प्राप्त करें।
    :param employee_id: कर्मचारी का आईडी, int.
    :return: यदि कर्मचारी पहले से एचआर प्रबंधन प्रणाली में है, तो कर्मचारी की जानकारी लौटाता है, अन्यथा, False लौटाता है।
    >>> hrManagementSystem = HRManagementSystem()
    >>> hrManagementSystem.employees = {1: {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}
    >>> hrManagementSystem.get_employee(1)
    {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}
    >>> hrManagementSystem.get_employee(2)
    False

    """
    if employee_id in self.employees:
        return self.employees[employee_id]
    else:
        return False

def list_employees(self):
    """
    HRManagementSystem में सभी कर्मचारियों की जानकारी सूचीबद्ध करें।
    :return: सभी कर्मचारियों की जानकारी की एक सूची, dict।
    >>> hrManagementSystem = HRManagementSystem()
    >>> hrManagementSystem.employees = {1: {'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}
    >>> hrManagementSystem.list_employees()
    {1: {'employee_ID': 1, 'name': 'John', 'position': 'Manager', 'department': 'Sales', 'salary': 100000}}

    """
    result = {}
    for employee_id, employee_info in self.employees.items():
        result[employee_id] = {'employee_ID': employee_id}
        result[employee_id].update(employee_info)
    return result

def format_line_html_text(self, html_text):
    """
    कोड के बिना एचटीएमएल टेक्स्ट प्राप्त करें, और जहां कोड है वहां -CODE- टैग जोड़ें
    :param html_text:string
    :return:string
    """
    from html.parser import HTMLParser

    class CodeReplacerParser(HTMLParser):
        def __init__(self):
            super().__init__()
            self.result = []
            self.in_code_block = False
            self.code_tags = {'pre', 'code'}
            self.tag_stack = []

        def handle_starttag(self, tag, attrs):
            self.tag_stack.append(tag)
            if tag in self.code_tags:
                self.in_code_block = True

        def handle_endtag(self, tag):
            if self.tag_stack and self.tag_stack[-1] == tag:
                self.tag_stack.pop()

            if tag in self.code_tags:
                # Check if we're still in a code block
                self.in_code_block = any(t in self.code_tags for t in self.tag_stack)

                # Add -CODE- marker when exiting code block
                if not self.in_code_block:
                    self.result.append('-CODE-')

        def handle_data(self, data):
            if not self.in_code_block:
                # Only add non-empty text
                text = data.strip()
                if text:
                    self.result.append(text)

    parser = CodeReplacerParser()
    parser.feed(html_text)

    # Join with newlines and return
    return '\n'.join(parser.result)

def extract_code_from_html_text(self, html_text):
    """
    एचटीएमएल बॉडी से कोड निकालें
    :param html_text: स्ट्रिंग, एचटीएमएल टेक्स्ट
    :return: कोड की सूची
    """
    from html.parser import HTMLParser

    class CodeExtractor(HTMLParser):
        def __init__(self):
            super().__init__()
            self.codes = []
            self.in_pre = False
            self.in_code = False
            self.current_code = []

        def handle_starttag(self, tag, attrs):
            if tag == 'pre':
                self.in_pre = True
                self.current_code = []
            elif tag == 'code' and self.in_pre:
                self.in_code = True

        def handle_endtag(self, tag):
            if tag == 'pre':
                if self.current_code:
                    code_text = ''.join(self.current_code).strip()
                    if code_text:
                        self.codes.append(code_text)
                self.in_pre = False
                self.in_code = False
                self.current_code = []
            elif tag == 'code':
                self.in_code = False

        def handle_data(self, data):
            if self.in_pre:
                self.current_code.append(data)

    parser = CodeExtractor()
    parser.feed(html_text)
    return parser.codes

def is_valid_move(self, pos1, pos2):
    """
    दो आइकनों की चाल को मान्य है या नहीं, यह जांचें (यानी, स्थान खेल बोर्ड की सीमा के भीतर हैं, दोनों स्थान समान नहीं हैं, दोनों स्थानों में समान आइकन हैं, और दोनों स्थानों के बीच एक मान्य पथ है)
    :param pos1: पहले आइकन की स्थिति ट्यूपल(x, y)
    :param pos2: दूसरे आइकन की स्थिति ट्यूपल(x, y)
    :return: True या False, जो दर्शाता है कि दो आइकनों की चाल मान्य है या नहीं
    """
    # Check if positions are the same
    if pos1 == pos2:
        return False

    # Check if positions are within board boundaries
    rows = len(self.board)
    cols = len(self.board[0]) if rows > 0 else 0

    x1, y1 = pos1
    x2, y2 = pos2

    if not (0 <= x1 < cols and 0 <= y1 < rows):
        return False
    if not (0 <= x2 < cols and 0 <= y2 < rows):
        return False

    # Check if both positions have the same icon
    if self.board[y1][x1] != self.board[y2][x2]:
        return False

    # Check if there's a valid path between the two positions
    # Mahjong Connect allows paths with at most 2 turns (3 line segments)
    return self._has_valid_path(pos1, pos2)

def _has_valid_path(self, pos1, pos2):
    """Helper method to check if there's a valid path with at most 2 turns"""
    x1, y1 = pos1
    x2, y2 = pos2

    # Try direct line (0 turns)
    if self._is_clear_horizontal(pos1, pos2) or self._is_clear_vertical(pos1, pos2):
        return True

    # Try 1 turn (L-shape)
    corner1 = (x2, y1)
    corner2 = (x1, y2)

    if self._is_empty_or_target(corner1, pos1, pos2):
        if self._is_clear_horizontal(pos1, corner1) and self._is_clear_vertical(corner1, pos2):
            return True

    if self._is_empty_or_target(corner2, pos1, pos2):
        if self._is_clear_vertical(pos1, corner2) and self._is_clear_horizontal(corner2, pos2):
            return True

    # Try 2 turns (Z-shape)
    # Check horizontal-vertical-horizontal
    for y in range(len(self.board)):
        mid1 = (x1, y)
        mid2 = (x2, y)
        if self._is_empty_or_target(mid1, pos1, pos2) and self._is_empty_or_target(mid2, pos1, pos2):
            if (self._is_clear_vertical(pos1, mid1) and 
                self._is_clear_horizontal(mid1, mid2) and 
                self._is_clear_vertical(mid2, pos2)):
                return True

    # Check vertical-horizontal-vertical
    for x in range(len(self.board[0])):
        mid1 = (x, y1)
        mid2 = (x, y2)
        if self._is_empty_or_target(mid1, pos1, pos2) and self._is_empty_or_target(mid2, pos1, pos2):
            if (self._is_clear_horizontal(pos1, mid1) and 
                self._is_clear_vertical(mid1, mid2) and 
                self._is_clear_horizontal(mid2, pos2)):
                return True

    return False

def _is_empty_or_target(self, pos, pos1, pos2):
    """Check if position is empty or one of the target positions"""
    if pos == pos1 or pos == pos2:
        return True
    x, y = pos
    return self.board[y][x] == '' or self.board[y][x] is None

def _is_clear_horizontal(self, pos1, pos2):
    """Check if horizontal path is clear"""
    x1, y1 = pos1
    x2, y2 = pos2
    if y1 != y2:
        return False

    start_x = min(x1, x2)
    end_x = max(x1, x2)

    for x in range(start_x, end_x + 1):
        if (x, y1) != pos1 and (x, y1) != pos2:
            if self.board[y1][x] != '' and self.board[y1][x] is not None:
                return False
    return True

def _is_clear_vertical(self, pos1, pos2):
    """Check if vertical path is clear"""
    x1, y1 = pos1
    x2, y2 = pos2
    if x1 != x2:
        return False

    start_y = min(y1, y2)
    end_y = max(y1, y2)

    for y in range(start_y, end_y + 1):
        if (x1, y) != pos1 and (x1, y) != pos2:
            if self.board[y][x1] != '' and self.board[y][x1] is not None:
                return False
    return True

def update(self, predicted_labels, true_labels):
    """
    सभी चार नमूनों (सच्चे सकारात्मक, झूठे सकारात्मक, झूठे नकारात्मक, सच्चे नकारात्मक) की संख्या को अपडेट करें
    :param predicted_labels: सूची, पूर्वानुमानित परिणाम
    :param true_labels: सूची, सच्चे लेबल
    :return: None, संबंधित नमूनों की संख्या में परिवर्तन करें
    >>> mc = MetricsCalculator()
    >>> mc.update([1, 1, 0, 0], [1, 0, 0, 1])
    (self.true_positives, self.false_positives, self.false_negatives, self.true_negatives) = (1, 1, 1, 1)
    """
    for predicted, true in zip(predicted_labels, true_labels):
        if predicted == 1 and true == 1:
            self.true_positives += 1
        elif predicted == 1 and true == 0:
            self.false_positives += 1
        elif predicted == 0 and true == 1:
            self.false_negatives += 1
        elif predicted == 0 and true == 0:
            self.true_negatives += 1

def sweep(self, x, y):
    """
    दिए गए स्थान को स्वीप करता है।
    :param x: स्थान का x समन्वय, int.
    :param y: स्थान का y समन्वय, int.
    :return: यदि खिलाड़ी ने खेल जीत लिया है तो True, अन्यथा False, यदि खेल अभी भी जारी है, तो खिलाड़ी का मानचित्र लौटाएं, list.
    >>> minesweeper_game = MinesweeperGame(3, 1)
    >>> minesweeper_game.minesweeper_map = [['X', 1, 0], [1, 1, 0], [0, 0, 0]]
    >>> minesweeper_game.player_map = [['-', '-', '-'], ['-', '-', '-'], ['-', '-', '-']]
    >>> minesweeper_game.sweep(1, 1)
    [['-', '-', '-'], ['-', 1, '-'], ['-', '-', '-']]

    """
    # Check if the position contains a mine
    if self.minesweeper_map[x][y] == 'X':
        return False

    # Reveal the cell
    self.player_map[x][y] = self.minesweeper_map[x][y]

    # If the cell is 0, recursively reveal adjacent cells
    if self.minesweeper_map[x][y] == 0:
        for dx in [-1, 0, 1]:
            for dy in [-1, 0, 1]:
                if dx == 0 and dy == 0:
                    continue
                nx, ny = x + dx, y + dy
                if 0 <= nx < len(self.minesweeper_map) and 0 <= ny < len(self.minesweeper_map[0]):
                    if self.player_map[nx][ny] == '-':
                        self.sweep(nx, ny)

    # Check if the player has won (all non-mine cells revealed)
    for i in range(len(self.minesweeper_map)):
        for j in range(len(self.minesweeper_map[0])):
            if self.minesweeper_map[i][j] != 'X' and self.player_map[i][j] == '-':
                return self.player_map

    return True

def switch_song(self):
    """
    प्लेलिस्ट में अगले गाने पर स्विच करता है।
    :return: यदि अगले गाने पर स्विच किया गया, तो True, यदि कोई अगला गाना नहीं है, तो False।
    >>> musicPlayer = MusicPlayer()
    >>> musicPlayer.playlist = ["song1", "song2"]
    >>> musicPlayer.current_song = "song1"
    >>> musicPlayer.switch_song()
    True

    """
    if not hasattr(self, 'playlist') or not self.playlist:
        return False

    if not hasattr(self, 'current_song') or self.current_song is None:
        return False

    try:
        current_index = self.playlist.index(self.current_song)
        if current_index < len(self.playlist) - 1:
            self.current_song = self.playlist[current_index + 1]
            return True
        else:
            return False
    except ValueError:
        return False

def previous_song(self):
    """
    प्लेलिस्ट में पिछले गाने पर स्विच करता है।
    :return: यदि पिछले गाने पर स्विच किया गया है तो True, यदि कोई पिछला गाना नहीं था तो False।
    >>> musicPlayer = MusicPlayer()
    >>> musicPlayer.playlist = ["song1", "song2"]
    >>> musicPlayer.current_song = "song2"
    >>> musicPlayer.previous_song()
    True

    """
    if not hasattr(self, 'playlist') or not self.playlist:
        return False

    if not hasattr(self, 'current_song') or self.current_song is None:
        return False

    try:
        current_index = self.playlist.index(self.current_song)
        if current_index > 0:
            self.current_song = self.playlist[current_index - 1]
            return True
        else:
            return False
    except ValueError:
        return False

@staticmethod
def binary_to_decimal(binary_num):
    """
    बाइनरी प्रारूप से दशमलव प्रारूप में एक संख्या को परिवर्तित करें।
    :param binary_num: str, बाइनरी संख्या
    :return: int, बाइनरी संख्या str का दशमलव प्रतिनिधित्व।
    >>> NumberConverter.binary_to_decimal('1010010110110111')
    42423
    """
    return int(binary_num, 2)

@staticmethod
def hex_to_decimal(hex_num):
    """
    एक संख्या को हेक्स प्रारूप से दशमलव प्रारूप में परिवर्तित करें।
    :param hex_num: str, हेक्स संख्या
    :return: int, हेक्स संख्या के दशमलव प्रतिनिधित्व।
    >>> NumberConverter.hex_to_decimal('a5b7')
    42423
    """
    return int(hex_num, 16)

def format(self, x):
    """
    एक संख्या को शब्दों के प्रारूप में परिवर्तित करता है
    :param x: int या float, वह संख्या जिसे शब्दों के प्रारूप में परिवर्तित किया जाना है
    :return: str, संख्या शब्दों के प्रारूप में
    >>> formatter = NumberWordFormatter()
    >>> formatter.format(123456)
    "ONE HUNDRED AND TWENTY THREE THOUSAND FOUR HUNDRED AND FIFTY SIX ONLY"
    """
    if x == 0:
        return "ZERO ONLY"

    # Handle negative numbers
    if x < 0:
        return "MINUS " + self.format(-x)

    # Handle decimal numbers
    if isinstance(x, float) and x != int(x):
        integer_part = int(x)
        decimal_part = round((x - integer_part) * 100)
        result = self.format(integer_part).replace(" ONLY", "")
        if decimal_part > 0:
            return result + " AND " + self.format(decimal_part).replace(" ONLY", "") + " PAISE ONLY"
        return result + " ONLY"

    x = int(x)

    ones = ["", "ONE", "TWO", "THREE", "FOUR", "FIVE", "SIX", "SEVEN", "EIGHT", "NINE"]
    teens = ["TEN", "ELEVEN", "TWELVE", "THIRTEEN", "FOURTEEN", "FIFTEEN", 
             "SIXTEEN", "SEVENTEEN", "EIGHTEEN", "NINETEEN"]
    tens = ["", "", "TWENTY", "THIRTY", "FORTY", "FIFTY", "SIXTY", "SEVENTY", "EIGHTY", "NINETY"]

    def convert_below_thousand(n):
        if n == 0:
            return ""
        elif n < 10:
            return ones[n]
        elif n < 20:
            return teens[n - 10]
        elif n < 100:
            return tens[n // 10] + (" " + ones[n % 10] if n % 10 != 0 else "")
        else:
            hundred_part = ones[n // 100] + " HUNDRED"
            remainder = n % 100
            if remainder > 0:
                return hundred_part + " AND " + convert_below_thousand(remainder)
            return hundred_part

    if x < 1000:
        return convert_below_thousand(x) + " ONLY"

    # Handle thousands and above
    parts = []

    # Millions
    if x >= 1000000:
        millions = x // 1000000
        parts.append(convert_below_thousand(millions) + " MILLION")
        x %= 1000000

    # Thousands
    if x >= 1000:
        thousands = x // 1000
        parts.append(convert_below_thousand(thousands) + " THOUSAND")
        x %= 1000

    # Remaining hundreds
    if x > 0:
        parts.append(convert_below_thousand(x))

    result = " ".join(parts) + " ONLY"
    return result

def send(self, info):
    """
    पते और सामग्री को शामिल करने वाली जानकारी भेजें
    :param info: dict, जानकारी का डिक्शनरी जिसमें पता और सामग्री शामिल है
    :return: यदि सफलतापूर्वक भेजा गया, तो कुछ नहीं लौटाएं; अन्यथा, एक स्ट्रिंग लौटाएं जो एक त्रुटि संदेश को इंगित करती है
    >>> server.send({"addr":66,"content":"ABC"})
    self.send_struct = {"addr":66,"content":"ABC"}
    """
    try:
        if not isinstance(info, dict):
            return "Error: info must be a dictionary"

        if "addr" not in info or "content" not in info:
            return "Error: info must contain 'addr' and 'content' keys"

        self.send_struct = info
        return None
    except Exception as e:
        return f"Error: {str(e)}"

def show(self, type):
    """
    निर्दिष्ट प्रकार की संरचना लौटाता है
    :param type: स्ट्रिंग, वह संरचना का प्रकार जो लौटाया जाएगा, जो 'send' या 'receive' हो सकता है
    :return: यदि type 'send' या 'receive' के बराबर है, तो संबंधित संरचना लौटाएं; अन्यथा, False लौटाएं
    >>> server.recv({"addr":88,"content":"abc"})
    >>> server.send({"addr":66,"content":"ABC"})
    >>> server.show("send")
    {"addr":66,"content":"ABC"}
    """
    if type == "send":
        return self._send_structure
    elif type == "receive":
        return self._receive_structure
    else:
        return False

def add_item(self, item, price, quantity=1):
    """
    खरीदारी सूची में आइटम की जानकारी जोड़ें, जिसमें कीमत और मात्रा शामिल हैं। डिफ़ॉल्ट मात्रा 1 है
    :param item: string, जोड़ा जाने वाला आइटम
    :param price: float, आइटम की कीमत
    :param quantity:int, आइटम की संख्या, डिफ़ॉल्ट 1 है
    :return:None
    >>> shoppingcart = ShoppingCart()
    >>> shoppingcart.add_item("apple", 1, 5)
    self.items = {"apple":{"price":1, "quantity":5}}
    """
    if not hasattr(self, 'items'):
        self.items = {}

    self.items[item] = {"price": price, "quantity": quantity}

@staticmethod
def mean(data):
    """
    दिए गए सूची का औसत निकालता है।
    :param data: दी गई सूची, सूची।
    :return: दी गई सूची का औसत, फ्लोट।
    >>> statistics3 = Statistics3()
    >>> statistics3.mean([1, 2, 3])
    2.0

    """
    if not data:
        return 0.0
    return sum(data) / len(data)

def is_board_full(self):
    """
    जांचें कि खेल का बोर्ड पूरी तरह से भरा हुआ है या नहीं।
    :return: bool, यह दर्शाता है कि खेल का बोर्ड भरा हुआ है या नहीं
    >>> ttt.is_board_full()
    False
    """
    for row in self.board:
        for cell in row:
            if cell is None or cell == '' or cell == ' ':
                return False
    return True

def _generate_cards(self):
    """
    कार्डों के लिए 1 और 9 के बीच यादृच्छिक संख्याएँ उत्पन्न करें।
    """
    import random
    return random.randint(1, 9)

import math

@staticmethod
def compute_idf_weight_dict(total_num, number_dict):
    """
    प्रत्येक गिनती के लिए log(total_num+1/count+1) की गणना करें जो number_dict में है
    :param total_num: int
    :param number_dict: dict
    :return: dict
    >>> num_dict = {'key1':0.1, 'key2':0.5}
    >>> VectorUtil.compute_idf_weight_dict(2, num_dict)
    {'key1': 1.0033021088637848, 'key2': 0.6931471805599453}
    """
    result_dict = {}
    for key, count in number_dict.items():
        result_dict[key] = math.log((total_num + 1) / (count + 1))
    return result_dict

def add_product(self, product_id, name, quantity):
    """
    इन्वेंटरी में उत्पाद जोड़ें और यदि यह पहले से इन्वेंटरी में मौजूद है तो मात्रा को बढ़ाएं।
    अन्यथा, बस नए उत्पाद को डिक्ट में जोड़ें।
    :param product_id: int
    :param name: str, उत्पाद का नाम
    :param quantity: int, उत्पाद की मात्रा
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 3}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity
    else:
        self.inventory[product_id] = {'name': name, 'quantity': quantity}

def update_product_quantity(self, product_id, quantity):
    """
    product_id के अनुसार, इन्वेंटरी में संबंधित उत्पाद की मात्रा में जोड़ें।
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.update_product_quantity(1, -1)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 2}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity

def text2int(self, textnum):
    """
    शब्द स्ट्रिंग को संबंधित पूर्णांक स्ट्रिंग में परिवर्तित करें
    :param textnum: स्ट्रिंग, परिवर्तित करने के लिए शब्द स्ट्रिंग
    :return: स्ट्रिंग, अंतिम परिवर्तित पूर्णांक स्ट्रिंग
    >>> w2n = Words2Numbers()
    >>> w2n.text2int("thirty-two")
    "32"
    """
    ones = {
        "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4,
        "five": 5, "six": 6, "seven": 7, "eight": 8, "nine": 9,
        "ten": 10, "eleven": 11, "twelve": 12, "thirteen": 13,
        "fourteen": 14, "fifteen": 15, "sixteen": 16, "seventeen": 17,
        "eighteen": 18, "nineteen": 19
    }

    tens = {
        "twenty": 20, "thirty": 30, "forty": 40, "fifty": 50,
        "sixty": 60, "seventy": 70, "eighty": 80, "ninety": 90
    }

    scales = {
        "hundred": 100,
        "thousand": 1000,
        "million": 1000000,
        "billion": 1000000000,
        "trillion": 1000000000000
    }

    textnum = textnum.lower().strip()

    if textnum in ones:
        return str(ones[textnum])

    # Replace hyphens and "and" with spaces
    textnum = textnum.replace("-", " ").replace(" and ", " ")
    words = textnum.split()

    current = 0
    result = 0

    for word in words:
        if word in ones:
            current += ones[word]
        elif word in tens:
            current += tens[word]
        elif word in scales:
            if word == "hundred":
                current *= scales[word]
            else:
                current *= scales[word]
                result += current
                current = 0

    result += current
    return str(result)

def read_zip_file(self):
    """
    खुला फ़ाइल ऑब्जेक्ट प्राप्त करें
    :return: यदि सफल, तो खुला फ़ाइल ऑब्जेक्ट लौटाता है; अन्यथा, None लौटाता है
    >>> zfp = ZipFileProcessor("aaa.zip")
    >>> file = zfp.read_zip_file()
    """
    import zipfile
    import os

    try:
        if hasattr(self, 'zip_file_path') and self.zip_file_path:
            if os.path.exists(self.zip_file_path):
                zip_file = zipfile.ZipFile(self.zip_file_path, 'r')
                return zip_file
            else:
                return None
        else:
            return None
    except Exception:
        return None
